1	using Toybox.Lang;
2	using Toybox.Activity;
3	
4	//! Base type for metric strategies (RunningStrategy, CyclingStrategy).
5	//! Enables static type checking on _strategy.buildPackets() dispatch.
6	//! Subclasses must implement: buildPackets(values as MetricValues) as Array<ByteArray>
7	class MetricStrategy {
8	    function initialize() {
9	    }
10	
11	    //! BLE 전송 주기 (초). 기본 5초, 서브클래스가 오버라이드 가능.
12	    //! 사이클 모드는 빠른 속도 변화 → 2초.
13	    function getTransmitIntervalSeconds() as Lang.Number {
14	        return 5;
15	    }
16	
17	    function buildPackets(values as MetricValues) as Lang.Array<Lang.ByteArray> {
18	        // Subclasses override. Default returns empty array.
19	        return [] as Lang.Array<Lang.ByteArray>;
20	    }
21	}
22	
23	//! Per-compute metric values container.
24	//! 매 compute() 호출마다 새로 채워지며 strategy 에 전달된다.
25	//! 누적 상태(예: HR 30초 락) 는 strategy 가 자체 보유한다.
26	//!
27	//! *Valid 플래그: 해당 메트릭이 실제 센서값인지(true) 또는 fallback 0인지(false).
28	//! Strategy.buildPackets() 가 이 플래그를 보고 stale 0 패킷을 iLens 로 보내지 않는다.
29	//! 기본값 false = "안 보내는 게 안전" (재연결 직후 0 패킷이 last value 를 덮어쓰는 결함 방지).
30	class MetricValues {
31	    public var elapsedSeconds as Lang.Number = 0;
32	    public var distance as Lang.Number = 0;        // meters
33	    public var paceSeconds as Lang.Number = 0;     // running only (sec/km)
34	    public var speedKmh as Lang.Float = 0.0;       // cycling only (km/h, Float for decimal precision)
35	    public var hr as Lang.Number = 0;              // 0 if unavailable
36	    public var cadence as Lang.Number = 0;         // running only (spm)
37	    public var altitudeM as Lang.Number = 0;       // cycling only (meters)
38	    public var totalAscent as Lang.Number = 0;     // cycling only (meters)
39	
40	    public var speedValid as Lang.Boolean = false;
41	    public var hrValid as Lang.Boolean = false;
42	    public var cadenceValid as Lang.Boolean = false;
43	    public var distanceValid as Lang.Boolean = false;
44	    public var altitudeValid as Lang.Boolean = false;
45	    public var totalAscentValid as Lang.Boolean = false;
46	
47	    function initialize() {
48	    }
49	
50	    //! 테스트 헬퍼: 모든 valid 플래그를 true 로. 기존 인코딩 회귀 테스트가 한 줄로 새 API 에 적응.
51	    function setAllValid() as Void {
52	        speedValid = true;
53	        hrValid = true;
54	        cadenceValid = true;
55	        distanceValid = true;
56	        altitudeValid = true;
57	        totalAscentValid = true;
58	    }
59	}
60	
61	//! sport 정수값으로부터 strategy 선택. 테스트 가능한 진입점.
62	//! Activity.SPORT_CYCLING → CyclingStrategy
