        grade = (altitudeDelta / distanceDelta) * 100.0;  // % 단위

        // 경사도 범위 제한 (-30% ~ +30%)
        if (grade < -30.0) { grade = -30.0; }
        if (grade > 30.0) { grade = 30.0; }

        // 다음 계산을 위해 저장
        _previousAltitude = altitude;
        _previousDistance = distance;
    }

